const input = $input.first().json;
const binary = $input.first().binary;
const ts = Date.now();

return [{
  json: {
    image_url: input.image_url || '',
    gancho: input.gancho || '',
    cuerpo: input.cuerpo || '',
    cta: input.cta || '',
    hashtags: input.hashtags || '',
    titulo_post: input.titulo_post || '',
    supabase_url: input.supabase_url || '',
    audio_filename: `influencer-audio-${ts}.mp3`,
    has_binary_audio: !!(binary && binary.audio_data)
  },
  binary: binary || {}
}];

const input = $('Preparar Nombre Audio').first().json;
const supabaseUrl = input.supabase_url || process.env.SUPABASE_URL || 'CONFIGURAR_SUPABASE_URL';
const audioUrl = `${supabaseUrl}/storage/v1/object/public/influencer-assets/${input.audio_filename}`;

return [{
  json: {
    image_url: input.image_url || '',
    gancho: input.gancho || '',
    cuerpo: input.cuerpo || '',
    cta: input.cta || '',
    hashtags: input.hashtags || '',
    titulo_post: input.titulo_post || '',
    audio_url: audioUrl
  }
}];

const input = $input.first().json;

const audioUrl = input.audio_url;
const imageUrl = input.image_url;
const gancho = (input.gancho || '').replace(/"/g, '\\"').replace(/\n/g, ' ');
const cuerpo = (input.cuerpo || '').replace(/"/g, '\\"').replace(/\n/g, ' ');
const cta = (input.cta || '').replace(/"/g, '\\"').replace(/\n/g, ' ');

const timeline = {
  timeline: {
    soundtrack: {
      src: audioUrl,
      effect: "fadeOut"
    },
    background: "#000000",
    tracks: [
      {
        clips: [
          {
            asset: {
              type: "html",
              html: `<div style="font-family:Inter,sans-serif;color:#D4AF37;font-size:42px;font-weight:800;text-align:center;padding:40px;text-shadow:2px 2px 8px rgba(0,0,0,0.8)">${gancho}</div>`,
              width: 1080,
              height: 400
            },
            start: 0,
            length: 5,
            position: "center",
            offset: { y: -0.15 },
            transition: { in: "fadeSlowDown", out: "fade" }
          },
          {
            asset: {
              type: "html",
              html: `<div style="font-family:Inter,sans-serif;color:#FFFFFF;font-size:32px;text-align:center;padding:40px;line-height:1.4;text-shadow:2px 2px 8px rgba(0,0,0,0.8)">${cuerpo}</div>`,
              width: 1080,
              height: 600
            },
            start: 5,
            length: 18,
            position: "center",
            transition: { in: "fade", out: "fade" }
          },
          {
            asset: {
              type: "html",
              html: `<div style="font-family:Inter,sans-serif;color:#D4AF37;font-size:38px;font-weight:700;text-align:center;padding:40px;text-shadow:2px 2px 8px rgba(0,0,0,0.8)">${cta}</div>`,
              width: 1080,
              height: 400
            },
            start: 23,
            length: 7,
            position: "center",
            offset: { y: 0.1 },
            transition: { in: "fadeSlowUp", out: "fade" }
          }
        ]
      },
      {
        clips: [
          {
            asset: {
              type: "html",
              html: `<div style="position:absolute;bottom:0;left:0;right:0;height:100%;background:linear-gradient(transparent 30%,rgba(0,0,0,0.7) 100%)"></div>`,
              width: 1080,
              height: 1920
            },
            start: 0,
            length: 30
          }
        ]
      },
      {
        clips: [
          {
            asset: {
              type: "image",
              src: imageUrl
            },
            start: 0,
            length: 30,
            fit: "cover",
            effect: "zoomIn"
          }
        ]
      }
    ]
  },
  output: {
    format: "mp4",
    fps: 30,
    size: {
      width: 1080,
      height: 1920
    }
  }
};

return [{ json: timeline }];

const response = $input.first().json;
const render = response.response;

if (render.status === 'done') {
  return [{
    json: {
      render_id: render.id,
      status: 'done',
      video_url: render.url,
      needs_polling: false,
      provider: 'shotstack'
    }
  }];
}

if (render.status === 'failed') {
  throw new Error(`Shotstack render fallo: ${render.error || 'Error desconocido'}`);
}

return [{
  json: {
    render_id: render.id,
    status: render.status,
    video_url: null,
    needs_polling: true
  }
}];
